#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX 1000
#define MAX_LEN 1000
// Define the Trie node structure
typedef struct TrieNode {
    struct TrieNode* children[26];
    int priority;
    char recipe[MAX_LEN];
} TrieNode;
// Function to create a new Trie node
TrieNode* createNode() {
    TrieNode* node = (TrieNode*)malloc(sizeof(TrieNode));
    for (int i = 0; i < 26; i++) {
        node->children[i] = NULL;
    }
    node->priority = -1;
    return node;
}
// Function to insert a recipe into the Trie
void insert(TrieNode* root, char* recipe, int priority) {
    TrieNode* node = root;
    for (int i = 0; i < strlen(recipe); i++) {
        int index = recipe[i] - 'a';
        if (node->children[index] == NULL) {
            node->children[index] = createNode();
        }
        node = node->children[index];
    }
    node->priority = priority;
    strcpy(node->recipe, recipe);
}
// Function to search for a recipe in the Trie
char* search(TrieNode* root, char* query) {
    TrieNode* node = root;
    for (int i = 0; i < strlen(query); i++) {
        int index = query[i] - 'a';
        if (node->children[index] == NULL) {
            return NULL;
        }
        node = node->children[index];
    }
    // Traverse the Trie to find the recipe with the highest priority
    char* result = NULL;
    int maxPriority = -1;
    while (node != NULL) {
        if (node->priority > maxPriority) {
            maxPriority = node->priority;
            result = node->recipe;
        }
        // Traverse all children
        for (int i = 0; i < 26; i++) {
            if (node->children[i] != NULL) {
                TrieNode* child = node->children[i];
                if (child->priority > maxPriority) {
                    maxPriority = child->priority;
                    result = child->recipe;
                }
            }
        }
        // Move to the next level
        node = NULL;
        for (int i = 0; i < 26; i++) {
            if (node->children[i] != NULL) {
                node = node->children[i];
                break;
            }
        }
    }
    return result;
}
int main() {
    int N;
    scanf("%d", &N);
    TrieNode* root = createNode();
    for (int i = 0; i < N; i++) {
        char recipe[MAX_LEN];
        int priority;
        scanf("%s %d", recipe, &priority);
        insert(root, recipe, priority);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        char query[MAX_LEN];
        scanf("%s", query);
        char* result = search(root, query);
        if (result == NULL) {
            printf("NO\n");
        } else {
            printf("%s\n", result);
        }
    }
    return 0;
}

