import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class Main {
    // Define the Trie node structure
    static class TrieNode {
        Map<Character, TrieNode> children;
        int priority;
        String recipe;
        public TrieNode() {
            children = new HashMap<>();
            priority = -1;
        }
    }
    // Function to create a new Trie node
    public static TrieNode createNode() {
        return new TrieNode();
    }
    // Function to insert a recipe into the Trie
    public static void insert(TrieNode root, String recipe, int priority) {
        TrieNode node = root;
        for (char c : recipe.toCharArray()) {
            if (!node.children.containsKey(c)) {
                node.children.put(c, createNode());
            }
            node = node.children.get(c);
        }
        node.priority = priority;
        node.recipe = recipe;
    }
    // Function to search for a recipe in the Trie
    public static String search(TrieNode root, String query) {
        TrieNode node = root;
        for (char c : query.toCharArray()) {
            if (!node.children.containsKey(c)) {
                return "";
            }
            node = node.children.get(c);
        }
        // Traverse the Trie to find the recipe with the highest priority
        String result = "";
        int maxPriority = -1;
        while (node != null) {
            if (node.priority > maxPriority) {
                maxPriority = node.priority;
                result = node.recipe;
            }
            // Traverse all children
            for (Map.Entry<Character, TrieNode> child : node.children.entrySet()) {
                TrieNode childNode = child.getValue();
                if (childNode.priority > maxPriority) {
                    maxPriority = childNode.priority;
                    result = childNode.recipe;
                }
            }
            // Move to the next level
            node = null;
            for (Map.Entry<Character, TrieNode> child : node.children.entrySet()) {
                TrieNode childNode = child.getValue();
                if (childNode != null) {
                    node = childNode;
                    break;
                }
            }
        }
        return result;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        TrieNode root = createNode();
        for (int i = 0; i < N; i++) {
            String recipe = scanner.next();
            int priority = scanner.nextInt();
            insert(root, recipe, priority);
        }
        int Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            String query = scanner.next();
            String result = search(root, query);
            if (result.isEmpty()) {
                System.out.println("NO");
            } else {
                System.out.println(result);
            }
        }
    }
}

